import json, os, re

# Load package data
pkg_path = locals()['var_functions.query_db:14']
with open(pkg_path, 'r') as f:
    packages = json.load(f)

# Parse to find latest release version for each NPM package
latest_packages = {}
for pkg in packages:
    if pkg['System'] != 'NPM':
        continue
    try:
        # Parse VersionInfo JSON string
        vinfo_str = pkg['VersionInfo'].replace('\n', ' ').strip()
        vinfo = json.loads(vinfo_str)

        if vinfo.get('IsRelease', False):
            name = pkg['Name']
            ordinal = vinfo.get('Ordinal', 0)

            if name not in latest_packages or ordinal > latest_packages[name]['ordinal']:
                latest_packages[name] = {
                    'Name': name,
                    'Version': pkg['Version'],
                    'ordinal': ordinal
                }
    except Exception as e:
        pass

print('Found', len(latest_packages), 'latest NPM package releases')
print('__RESULT__:', json.dumps(list(latest_packages.values())[:5]))

