import json, re

# Load all data
pkg_data = json.load(open(locals()['var_functions.query_db:52'],'r'))
map_data = json.load(open(locals()['var_functions.query_db:34'],'r'))
proj_data = json.load(open(locals()['var_functions.query_db:66'],'r'))

print('Loaded:', len(pkg_data), 'packages,', len(map_data), 'mappings,', len(proj_data), 'projects')

# Step 1: Find latest release for each package
latest = {}
for item in pkg_data:
    if item['System'] != 'NPM':
        continue
    try:
        vinfo = json.loads(item['VersionInfo'].replace('\n',' ').strip())
        if vinfo.get('IsRelease'):
            name = item['Name']
            ordinal = vinfo['Ordinal']
            version = item['Version']
            if name not in latest or ordinal > latest[name][1]:
                latest[name] = (version, ordinal)
    except Exception as e:
        pass

# Step 2: Build GitHub mappings
gh_map = { (m['Name'], m['Version']): m['ProjectName'] 
           for m in map_data if m.get('ProjectType') == 'GITHUB' }

# Step 3: Build stars map
stars = {}
for proj in proj_data:
    info = proj['Project_Information']
    m = re.search(r'project\s+([^\s]+/[^\s]+)', info)
    if m:
        repo = m.group(1)
        m2 = re.search(r'(\d+\,?\d*)\s+stars', info)
        if m2:
            stars[repo] = int(m2.group(1).replace(',',''))

# Step 4: Combine
candidates = []
for name in latest:
    ver = latest[name][0]
    key = (name, ver)
    if key in gh_map:
        repo = gh_map[key]
        if repo in stars:
            candidates.append({
                'PackageName': name,
                'Version': ver,
                'GitHubRepo': repo,
                'Stars': stars[repo]
            })

# Get top 5
top = sorted(candidates, key=lambda x: x['Stars'], reverse=True)[:5]

for i, pkg in enumerate(top, 1):
    print(f"{i}. {pkg['PackageName']} {pkg['Version']} - {pkg['GitHubRepo']} - {pkg['Stars']:,} stars")

print('__RESULT__:')
print(json.dumps(top, indent=2))

