import json, re

# Load all datasets
with open(locals()['var_functions.query_db:52']) as f:
    packages = json.load(f)

with open(locals()['var_functions.query_db:34']) as f:
    mappings = json.load(f)

with open(locals()['var_functions.query_db:66']) as f:
    projects = json.load(f)

# Step 1: Find latest release for each NPM package
latest = {}
for p in packages:
    if p.get('System') != 'NPM':
        continue
    try:
        vinfo_obj = json.loads(p['VersionInfo'])
        if vinfo_obj.get('IsRelease'):
            name = p['Name']
            ordinal = vinfo_obj['Ordinal']
            if name not in latest or ordinal > latest[name][1]:
                latest[name] = (p['Version'], ordinal)
    except:
        continue

print('Packages with latest releases:', len(latest))

# Step 2: Build GitHub project mapping table
gh_map = {}
for m in mappings:
    if m.get('ProjectType') == 'GITHUB':
        key = (m['Name'], m['Version'])
        gh_map[key] = m['ProjectName']

print('GitHub project mappings:', len(gh_map))

# Step 3: Extract stars from project information
stars_map = {}
for proj in projects:
    info = proj['Project_Information']
    m = re.search(r'project\s+([^\s]+/[^\s]+)', info)
    if not m:
        continue
    repo = m.group(1)
    m2 = re.search(r'(\d+[\d,]*)\s+stars', info)
    if not m2:
        continue
    stars = int(m2.group(1).replace(',', ''))
    stars_map[repo] = stars

print('Projects with star data:', len(stars_map))

# Step 4: Combine everything and find top 5
candidates = []
for name in latest:
    version = latest[name][0]
    key = (name, version)
    if key in gh_map:
        repo = gh_map[key]
        if repo in stars_map:
            candidates.append({
                'Package': name,
                'Version': version,
                'Repository': repo,
                'Stars': stars_map[repo]
            })

print('Total matched packages:', len(candidates))

# Step 5: Get top 5 by stars
top5 = sorted(candidates, key=lambda x: x['Stars'], reverse=True)[:5]

print('\nTop 5 NPM Packages by GitHub Stars:')
for i, item in enumerate(top5, 1):
    print('%d. %s v%s' % (i, item['Package'], item['Version']))
    print('   Repository: %s' % item['Repository'])
    print('   Stars: %s' % format(item['Stars'], ','))
    print()

result = {'top_packages': top5}
print('__RESULT__:')
print(json.dumps(result))

