import json
import re

# Step 1: Load data from all three file paths
pkg_path = locals()['var_functions.query_db:52']
mappings_path = locals()['var_functions.query_db:34']
projects_path = locals()['var_functions.query_db:66']

with open(pkg_path) as f1:
    npm_packages = json.load(f1)

with open(mappings_path) as f2:
    project_mappings = json.load(f2)

with open(projects_path) as f3:
    project_info_list = json.load(f3)

# Step 2: For each NPM package, find the latest release (highest ordinal for release versions)
print('Step 2: Finding latest releases...')
latest_versions = {}

for package in npm_packages:
    if package['System'] != 'NPM':
        continue
    try:
        version_info = json.loads(package['VersionInfo'].replace('\n', ' ').strip())
        if version_info.get('IsRelease'):
            name = package['Name']
            ordinal = version_info['Ordinal']
            if name not in latest_versions or ordinal > latest_versions[name]['ordinal']:
                latest_versions[name] = {
                    'version': package['Version'],
                    'ordinal': ordinal
                }
    except:
        continue

print(f'Found {len(latest_versions)} NPM packages with latest releases')

# Step 3: Build mapping from package to GitHub repository
github_map = {}
for mapping in project_mappings:
    if mapping.get('ProjectType') == 'GITHUB':
        key = (mapping['Name'], mapping['Version'])
        github_map[key] = mapping['ProjectName']

print(f'GitHub project mappings: {len(github_map)}')

# Step 4: Extract GitHub star counts from project info
stars_by_repo = {}
for project in project_info_list:
    info = project['Project_Information']
    repo_match = re.search(r'project\s+([^\s]+/[^\s]+)', info)
    if repo_match:
        repo = repo_match.group(1)
        stars_match = re.search(r'(\d[\d,]*)\s+stars', info)
        if stars_match:
            stars_str = stars_match.group(1).replace(',', '')
            try:
                stars = int(stars_str)
                stars_by_repo[repo] = stars
            except:
                pass

print(f'Repositories with star data: {len(stars_by_repo)}')

# Step 5: Find matching packages and rank by stars
candidate_packages = []

for name, data in latest_versions.items():
    key = (name, data['version'])
    if key in github_map:
        repo = github_map[key]
        if repo in stars_by_repo:
            candidate_packages.append({
                'PackageName': name,
                'Version': data['version'],
                'GitHubRepository': repo,
                'Stars': stars_by_repo[repo]
            })

print(f'Matched packages: {len(candidate_packages)}')

# Step 6: Sort by stars and get top 5
top5 = sorted(candidate_packages, key=lambda x: x['Stars'], reverse=True)[:5]

print('Top 5 NPM packages by GitHub stars:')
for i, pkg in enumerate(top5, 1):
    print(f"{i}. {pkg['PackageName']} v{pkg['Version']}")
    print(f"   Repository: {pkg['GitHubRepository']}")
    print(f"   Stars: {pkg['Stars']:,}")
    print()

# Return result
result = {'packages': top5}
print('__RESULT__:')
print(json.dumps(result))

