import json
import re
from collections import defaultdict

# Load all three datasets
def load_json(path):
    with open(path, 'r') as f:
        return json.load(f)

packages = load_json(locals()['var_functions.query_db:52'])
mappings = load_json(locals()['var_functions.query_db:34'])
projects = load_json(locals()['var_functions.query_db:66'])

print(f"Loaded {len(packages)} packages, {len(mappings)} mappings, {len(projects)} projects")

# Step 1: Find latest release version for each NPM package
latest_pkg = {}
for pkg in packages:
    if pkg['System'] != 'NPM':
        continue
    try:
        # Parse the VersionInfo string which contains JSON data
        vinfo_str = pkg['VersionInfo']
        # json.loads should handle it properly even with escaped newlines
        vinfo = json.loads(vinfo_str)
        if vinfo.get('IsRelease', False):
            name = pkg['Name']
            ordinal = vinfo.get('Ordinal', 0)
            if name not in latest_pkg or ordinal > latest_pkg[name]['ordinal']:
                latest_pkg[name] = {
                    'version': pkg['Version'],
                    'ordinal': ordinal
                }
    except Exception as e:
        # Skip problematic entries
        continue

print(f"Found {len(latest_pkg)} NPM packages with latest releases")

# Step 2: Create mapping from package+version to GitHub repository
gh_map = {}
for m in mappings:
    if m.get('ProjectType') == 'GITHUB':
        key = (m['Name'], m['Version'])
        gh_map[key] = m['ProjectName']

print(f"GitHub project mappings: {len(gh_map)}")

# Step 3: Extract GitHub star counts from project info
stars_map = {}
for proj in projects:
    info = proj.get('Project_Information', '')
    # Extract repository name (owner/repo format)
    m = re.search(r'project\s+([^\s/]+/[^\s]+)', info)
    if m:
        repo = m.group(1)
        # Extract stars count
        m2 = re.search(r'(\d+[\d,]*)\s+stars', info)
        if m2:
            try:
                stars = int(m2.group(1).replace(',', ''))
                stars_map[repo] = stars
            except:
                pass

print(f"Projects with star data: {len(stars_map)}")

# Step 4: Find matches and rank by stars
candidates = []
for name, data in latest_pkg.items():
    key = (name, data['version'])
    if key in gh_map:
        repo = gh_map[key]
        if repo in stars_map:
            candidates.append({
                'PackageName': name,
                'Version': data['version'],
                'GitHubRepository': repo,
                'Stars': stars_map[repo]
            })

print(f"Total matched packages: {len(candidates)}")

# Sort by stars and get top 5
sorted_candidates = sorted(candidates, key=lambda x: x['Stars'], reverse=True)
top5 = sorted_candidates[:5]

print("\nTOP 5 NPM PACKAGES BY GITHUB STARS:")
for i, pkg in enumerate(top5, 1):
    print(f"{i}. {pkg['PackageName']} (v{pkg['Version']})")
    print(f"   Repository: {pkg['GitHubRepository']}")
    print(f"   Stars: {pkg['Stars']:,}")
    print()

# Prepare final result
result = {"top5_packages": top5}

print('__RESULT__:')
print(json.dumps(result))

