for p in packages:
    if p.get('System') == 'NPM':
        vinfo_str = p['VersionInfo']
        vinfo = json.loads(vinfo_str.replace('\n',' ').replace('\r','').strip())
        if vinfo['IsRelease']:
            name = p['Name']
            ordinal = vinfo['Ordinal']
            if name not in latest_pkg or ordinal > latest_pkg[name][1]:
                latest_pkg[name] = (p['Version'], ordinal)

# Step 2: Build GitHub mapping
github_map = {}
for m in mappings:
    if m.get('ProjectType') == 'GITHUB':
        github_map[(m['Name'], m['Version'])] = m['ProjectName']

# Step 3: Extract stars
stars = {}
for proj in projects:
    info = proj['Project_Information']
    m = re.search(r'project\s+([^\s]+/[^\s]+)', info)
    if m:
        repo = m.group(1)
        m2 = re.search(r'(\d+[\d,]*)\s+stars', info, re.IGNORECASE)
        if m2:
            stars[repo] = int(m2.group(1).replace(',',''))

# Step 4: Combine and rank
candidates = []
for name, (version, _) in latest_pkg.items():
    key = (name, version)
    if key in github_map and github_map[key] in stars:
        repo = github_map[key]
        candidates.append({
            'PackageName': name,
            'Version': version,
            'GitHubRepository': repo,
            'Stars': stars[repo]
        })

# Step 5: Get top 5
top5 = sorted(candidates, key=lambda x: x['Stars'], reverse=True)[:5]

print('Top 5 NPM packages by GitHub stars:')
for i, pkg in enumerate(top5, 1):
    print(f"{i}. {pkg['PackageName']} v{pkg['Version']}")
    print(f"   Repository: {pkg['GitHubRepository']}")
    print(f"   Stars: {pkg['Stars']:,}")
    print()

result = {'packages': top5}
print('__RESULT__:')
print(json.dumps(result))

